function Test-HqPhoneDashboardSecurityModel {
    $indexPath = Join-Path $fleetRoot "docs\index.html"
    $cssPath = Join-Path $fleetRoot "docs\assets\phone-hq.css"
    $jsPath = Join-Path $fleetRoot "docs\assets\phone-hq.js"
    $dashboardPath = Join-Path $fleetRoot "docs\fleet\PHONE_HQ_DASHBOARD.md"
    $securityPath = Join-Path $fleetRoot "docs\fleet\PHONE_HQ_SECURITY_MODEL.md"
    $readmePath = Join-Path $fleetRoot "README.md"

    foreach ($path in @($indexPath, $cssPath, $jsPath, $dashboardPath, $securityPath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "Phone HQ static file exists: $path"
    }

    $indexText = Get-Content -LiteralPath $indexPath -Raw -ErrorAction Stop
    $cssText = Get-Content -LiteralPath $cssPath -Raw -ErrorAction Stop
    $jsText = Get-Content -LiteralPath $jsPath -Raw -ErrorAction Stop
    $dashboardText = Get-Content -LiteralPath $dashboardPath -Raw -ErrorAction Stop
    $securityText = Get-Content -LiteralPath $securityPath -Raw -ErrorAction Stop
    $readmeText = Get-Content -LiteralPath $readmePath -Raw -ErrorAction Stop
    $combinedText = @($indexText, $dashboardText, $securityText) -join "`n"
    $requiredPhoneHqLinks = @(
        "https://github.com/scolety1/Thousand-Sunny-Fleet/blob/main/fleet/status/current.md",
        "https://github.com/scolety1/Thousand-Sunny-Fleet/blob/main/fleet/status/today.md",
        "https://github.com/scolety1/Thousand-Sunny-Fleet/edit/main/fleet/control/quick-mission.md",
        "https://github.com/scolety1/Thousand-Sunny-Fleet/edit/main/fleet/control/emergency.md",
        "https://github.com/scolety1/Thousand-Sunny-Fleet/blob/main/fleet/control/mission.md",
        "https://github.com/scolety1/Thousand-Sunny-Fleet/blob/main/docs/fleet/REMOTE_TRAVEL_CODEX_THIN_PROMPT_PACKET.md",
        "https://github.com/scolety1/Thousand-Sunny-Fleet/blob/main/docs/fleet/PHONE_HQ_SECURITY_MODEL.md"
    )

    foreach ($phrase in @(
        "This public dashboard is request-only. It does not execute Codex, approve deployments, or grant authority.",
        "Fleet status",
        "Travel readiness",
        "Today Log",
        "Quick Mission Request",
        "Emergency Stop Request",
        "Safe From Phone",
        "Not Safe From Phone",
        "Travel Codex Prompt Packet",
        "Request-only",
        "View-only",
        "Forbidden from phone",
        "statusCaution",
        "caution-only"
    )) {
        Assert-True -Condition ($indexText -match [regex]::Escape($phrase)) -Message "Phone HQ dashboard preserves mobile/security phrase: $phrase"
    }

    foreach ($phrase in @(
        "GitHub Pages serves static files",
        "request-only",
        "does not execute Codex",
        "browser must never store GitHub personal access tokens",
        "browser must never directly execute shell commands",
        "future mobile control plane must be separate",
        "Remote access and phone access grant no extra authority",
        "Product repo access must be separately scoped",
        "Loaded public status is view-only and never authority",
        "Dashboard JavaScript may read public-safe status only"
    )) {
        Assert-True -Condition ($securityText -match [regex]::Escape($phrase)) -Message "Phone HQ security model preserves boundary: $phrase"
    }

    foreach ($pattern in @(
        "(?i)ghp_[A-Za-z0-9_]{20,}",
        "(?i)github_pat_[A-Za-z0-9_]{20,}",
        "(?i)sk-[A-Za-z0-9]{20,}",
        "BEGIN [A-Z ]*PRIVATE KEY",
        "(?i)access_token\s*=",
        "(?i)client_secret\s*=",
        "(?i)password\s*="
    )) {
        Assert-False -Condition ($combinedText -match $pattern) -Message "Phone HQ docs do not contain token-like secret pattern: $pattern"
    }

    Assert-False -Condition ($indexText -match '<script\s+src="https?://') -Message "Phone HQ has no external script src"
    Assert-False -Condition ($indexText -match '<link[^>]+href="https?://') -Message "Phone HQ has no external stylesheet or font link"
    Assert-True -Condition ($indexText -match 'href="\./assets/phone-hq\.css"' -and $indexText -match 'src="\./assets/phone-hq\.js"') -Message "Phone HQ uses local CSS and JS assets"
    Assert-True -Condition (Test-Path -LiteralPath $cssPath) -Message "Phone HQ local CSS asset path exists"
    Assert-True -Condition (Test-Path -LiteralPath $jsPath) -Message "Phone HQ local JS asset path exists"
    Assert-False -Condition ($indexText -match '<img[^>]+src="https?://') -Message "Phone HQ has no external image src"
    Assert-False -Condition ($indexText -match '<iframe\b') -Message "Phone HQ has no iframe embeds"
    Assert-False -Condition ($indexText -match '(?i)(analytics|gtag|googletagmanager|google-analytics|plausible|segment|mixpanel|hotjar|adservice|doubleclick)') -Message "Phone HQ has no analytics, trackers, or ad scripts"
    Assert-False -Condition ($cssText -match '@import|url\(\s*["'']?https?://') -Message "Phone HQ CSS has no external imports, images, fonts, or styles"
    Assert-False -Condition ($indexText -match 'target="_blank"(?![^>]+rel="noopener noreferrer")') -Message "Phone HQ new-tab links use noopener noreferrer when present"
    Assert-False -Condition ($jsText -match '\b(localStorage|sessionStorage)\b') -Message "Phone HQ JS does not store browser credentials or state"
    Assert-False -Condition ($jsText -match '\bPOST\b|method\s*:|github\.com/.*/actions|workflow_dispatch') -Message "Phone HQ JS does not write, trigger Actions, or submit commands"
    Assert-False -Condition ($jsText -match 'https://(?!raw\.githubusercontent\.com/scolety1/Thousand-Sunny-Fleet/main/fleet/status/(current\.md|projects\.json))') -Message "Phone HQ JS does not call external command backends"
    Assert-True -Condition ($cssText -match "status-caution") -Message "Phone HQ CSS styles the caution-only status guard"

    foreach ($href in $requiredPhoneHqLinks) {
        Assert-True -Condition ($indexText -match [regex]::Escape($href)) -Message "Phone HQ public dashboard preserves required link: $href"
    }

    foreach ($phrase in @(
        "Link And Asset Integrity",
        "latest status",
        "today log",
        "quick mission request",
        "emergency stop request",
        "mission control",
        "travel Codex prompt packet",
        "security model",
        'Static assets must stay local under `docs/assets`',
        "Do not add external scripts",
        'If a future external link opens in a new tab, it must use `rel="noopener noreferrer"`',
        "Link presence is navigation only"
    )) {
        Assert-True -Condition ($dashboardText -match [regex]::Escape($phrase)) -Message "Phone HQ dashboard docs preserve link/asset integrity rule: $phrase"
    }

    foreach ($phrase in @(
        "must not load third-party scripts",
        "third-party stylesheets",
        "external images",
        "iframes",
        "trackers",
        "analytics",
        "ad scripts",
        "external font CDNs",
        "Required Phone HQ links are navigation only"
    )) {
        Assert-True -Condition ($securityText -match [regex]::Escape($phrase)) -Message "Phone HQ security model preserves no-third-party-loading rule: $phrase"
    }

    foreach ($phrase in @(
        "unsafeStatusPatterns",
        "statusNeedsCaution",
        "Loaded status contains active-looking or execution-looking language",
        "Caution-only; phone actions remain requests",
        "Live status did not load",
        "do not execute from phone",
        "request-only rules"
    )) {
        Assert-True -Condition ($jsText -match [regex]::Escape($phrase)) -Message "Phone HQ JS preserves stale status guard phrase: $phrase"
    }

    foreach ($phrase in @(
        "\bACTIVE\b",
        "push\s*=\s*true",
        "\ball-fleet\b",
        "\bovernight\b",
        "\bdeploy\b",
        "runtime command binding",
        "phone approval"
    )) {
        Assert-True -Condition ($jsText -match [regex]::Escape($phrase)) -Message "Phone HQ JS treats active-looking status as caution-only: $phrase"
    }

    foreach ($phrase in @(
        "Stale Or Active-Looking Status",
        "view-only public status, not authority",
        "treat it as caution-only and follow request-only rules",
        "If live status loading fails",
        "do not trigger GitHub Actions",
        "do not execute Codex from phone text"
    )) {
        Assert-True -Condition ($dashboardText -match [regex]::Escape($phrase)) -Message "Phone HQ dashboard doc preserves stale status guard: $phrase"
    }

    foreach ($forbiddenBoundary in @(
        "No public RDP or router port forwarding.",
        "No all-fleet or overnight runners.",
        "No runtime command binding or phone approval authority.",
        "No product-repo mutation.",
        "No deploys, commits, pushes, staging, installs, or migrations."
    )) {
        Assert-True -Condition ($indexText -match [regex]::Escape($forbiddenBoundary)) -Message "Phone HQ dashboard preserves forbidden boundary: $forbiddenBoundary"
    }

    Assert-True -Condition ($dashboardText -match "Hosted dashboard: \[Thousand Sunny Fleet HQ\]\(https://scolety1.github.io/Thousand-Sunny-Fleet/\)") -Message "Phone HQ dashboard doc links hosted URL"
    Assert-True -Condition ($dashboardText -match "PHONE_HQ_SECURITY_MODEL.md") -Message "Phone HQ dashboard doc references security model"
    Assert-True -Condition ($readmeText -match "PHONE_HQ_SECURITY_MODEL.md") -Message "README references Phone HQ security model"
}

function Test-HqPhoneProjectStatusDashboard {
    $indexPath = Join-Path $fleetRoot "docs\index.html"
    $jsPath = Join-Path $fleetRoot "docs\assets\phone-hq.js"
    $generatorPath = Join-Path $fleetRoot "tools\fleet-project-status.ps1"
    $statusJsonPath = Join-Path $fleetRoot "fleet\status\projects.json"
    $statusMdPath = Join-Path $fleetRoot "fleet\status\projects.md"
    $dashboardPath = Join-Path $fleetRoot "docs\fleet\PHONE_HQ_DASHBOARD.md"
    $securityPath = Join-Path $fleetRoot "docs\fleet\PHONE_HQ_SECURITY_MODEL.md"
    $roadmapPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_ROADMAP.md"

    foreach ($path in @($indexPath, $jsPath, $generatorPath, $statusJsonPath, $statusMdPath, $dashboardPath, $securityPath, $roadmapPath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "Phone HQ project-first file exists: $path"
    }

    $fixtureDir = Join-Path $fixtureRoot "phone-hq-project-status"
    $fixtureConfig = Join-Path $fixtureDir "projects.json"
    $fixtureOutput = Join-Path $fixtureDir "out"
    New-Item -ItemType Directory -Force -Path $fixtureDir | Out-Null
    @(
        [pscustomobject]@{
            name = "PrivateLens"
            repo = "C:\Users\codex-agent\PrivateLensSecretFixture"
            profile = "experimental-prototype"
            projectType = "ai-workflow"
            riskTier = "local-only"
        },
        [pscustomobject]@{
            name = "ArchivedFixture"
            repo = "C:\Users\codex-agent\ArchivedSecretFixture"
            profile = "experimental-prototype"
            projectType = "sandbox-prototype"
            riskTier = "local-only"
            archived = $true
        }
    ) | ConvertTo-Json -Depth 6 | Set-Content -LiteralPath $fixtureConfig -Encoding UTF8

    & powershell -NoProfile -ExecutionPolicy Bypass -File $generatorPath -ConfigPath $fixtureConfig -OutputDirectory $fixtureOutput *> $null

    $fixtureJsonPath = Join-Path $fixtureOutput "projects.json"
    $fixtureMdPath = Join-Path $fixtureOutput "projects.md"
    Assert-True -Condition (Test-Path -LiteralPath $fixtureJsonPath) -Message "Project status generator writes JSON snapshot"
    Assert-True -Condition (Test-Path -LiteralPath $fixtureMdPath) -Message "Project status generator writes Markdown snapshot"

    $generatedJson = Get-Content -LiteralPath $fixtureJsonPath -Raw -ErrorAction Stop
    $generatedMd = Get-Content -LiteralPath $fixtureMdPath -Raw -ErrorAction Stop
    $generated = "$generatedJson`n$generatedMd"
    $parsed = $generatedJson | ConvertFrom-Json

    Assert-True -Condition ($parsed.statusKind -eq "public-safe-project-status-snapshot") -Message "Project status snapshot has public-safe status kind"
    Assert-True -Condition (@($parsed.projects).Count -eq 2) -Message "Project status fixture emits active and archived projects"
    Assert-True -Condition ($generated -match "PrivateLens") -Message "Project status generator can represent PrivateLens"
    Assert-True -Condition ($generated -match "ArchivedFixture") -Message "Project status generator can represent archived projects"
    $archivedFixtureProject = @($parsed.projects | Where-Object { [string]$_.name -eq "ArchivedFixture" })[0]
    Assert-Equal -Actual ([string]$archivedFixtureProject.statusColor) -Expected "ARCHIVED" -Message "Archived project status is ARCHIVED"
    Assert-Equal -Actual ([string]$archivedFixtureProject.branch) -Expected "archived" -Message "Archived project does not inspect branch"
    Assert-Equal -Actual ([string]$archivedFixtureProject.cleanState) -Expected "archived" -Message "Archived project does not inspect clean state"
    Assert-Equal -Actual ([bool]$archivedFixtureProject.archived) -Expected $true -Message "Archived project snapshot carries archived flag"
    Assert-True -Condition ([string]$archivedFixtureProject.nextRecommendedAction -match "Leave archived") -Message "Archived project next action stays parked"
    Assert-False -Condition ($generated -match "C:\\Users\\|C:/Users/|PrivateLensSecretFixture|ArchivedSecretFixture") -Message "Generated project status omits local absolute Windows user paths"
    Assert-False -Condition ($generated -match "C:\\Dev\\|C:/Dev/") -Message "Generated project status omits local Dev paths"

    foreach ($pattern in @(
        "(?i)ghp_[A-Za-z0-9_]{20,}",
        "(?i)github_pat_[A-Za-z0-9_]{20,}",
        "(?i)sk-[A-Za-z0-9]{20,}",
        "BEGIN [A-Z ]*PRIVATE KEY",
        "(?i)access_token\s*=",
        "(?i)client_secret\s*=",
        "(?i)password\s*="
    )) {
        Assert-False -Condition ($generated -match $pattern) -Message "Generated project status has no secret-like pattern: $pattern"
    }

    $realGenerated = (Get-Content -LiteralPath $statusJsonPath -Raw -ErrorAction Stop) + "`n" + (Get-Content -LiteralPath $statusMdPath -Raw -ErrorAction Stop)
    Assert-False -Condition ($realGenerated -match "C:\\Users\\|C:\\Dev\\|C:/Users/|C:/Dev/") -Message "Real generated project status omits local absolute paths"
    Assert-False -Condition ($realGenerated -match "(?i)ghp_|github_pat_|sk-|BEGIN [A-Z ]*PRIVATE KEY|access_token\s*=|client_secret\s*=|password\s*=") -Message "Real generated project status has no common secret/token placeholders"

    $indexText = Get-Content -LiteralPath $indexPath -Raw -ErrorAction Stop
    $jsText = Get-Content -LiteralPath $jsPath -Raw -ErrorAction Stop
    $dashboardText = Get-Content -LiteralPath $dashboardPath -Raw -ErrorAction Stop
    $securityText = Get-Content -LiteralPath $securityPath -Raw -ErrorAction Stop
    $roadmapText = Get-Content -LiteralPath $roadmapPath -Raw -ErrorAction Stop
    $buttonLabels = @([regex]::Matches($indexText, '<a[^>]+class="[^"]*\bbutton\b[^"]*"[^>]*>([^<]+)</a>') | ForEach-Object { $_.Groups[1].Value })
    $combinedDocs = "$dashboardText`n$securityText`n$roadmapText"

    foreach ($phrase in @(
        "Project Control",
        "Current Projects",
        "projectSnapshotState",
        "Phone HQ is request/status only. It does not execute Codex, approve work, merge, push, or deploy."
    )) {
        Assert-True -Condition ($indexText -match [regex]::Escape($phrase)) -Message "Phone HQ index preserves project-first phrase: $phrase"
    }

    foreach ($label in @("Request task", "Stop request", "Open log")) {
        Assert-True -Condition (($indexText -match [regex]::Escape($label)) -or ($jsText -match [regex]::Escape($label))) -Message "Phone HQ controls use request-only wording: $label"
    }

    foreach ($badLabel in @("Run Codex", "Deploy", "Push", "Merge", "Approve")) {
        Assert-False -Condition (@($buttonLabels | Where-Object { $_ -match "^$([regex]::Escape($badLabel))$" }).Count -gt 0) -Message "Phone HQ button/control labels avoid direct execution wording: $badLabel"
    }

    foreach ($phrase in @(
        "project-first",
        "generated public-safe project status snapshots",
        "local absolute paths",
        "Snapshot status can be stale",
        "Actual Codex execution remains local, bounded, one-project/one-task",
        "future authenticated control plane must be separate"
    )) {
        Assert-True -Condition ($combinedDocs -match [regex]::Escape($phrase)) -Message "Phone HQ docs preserve generated project snapshot boundary: $phrase"
    }

    foreach ($phrase in @(
        "all-fleet",
        "overnight",
        "product-repo mutation",
        "merge, push, deploy",
        "phone approval authority"
    )) {
        Assert-True -Condition ($combinedDocs -match [regex]::Escape($phrase)) -Message "Phone HQ docs preserve forbidden phone boundary: $phrase"
    }
}

function Test-HqOneProjectProofRunWorkflow {
    $workflowPath = Join-Path $fleetRoot "docs\fleet\ONE_PROJECT_PROOF_RUN_WORKFLOW.md"
    $examplePath = Join-Path $fleetRoot "docs\fleet\ONE_PROJECT_PROOF_RUN_PRIVATE_LENS_EXAMPLE.md"
    $roadmapPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_ROADMAP.md"
    $queuePath = Join-Path $fleetRoot "docs\fleet\HQ_REPAIR_TASK_QUEUE.md"
    $preflightPath = Join-Path $fleetRoot "tools\fleet-proof-run-preflight.ps1"

    foreach ($path in @($workflowPath, $examplePath, $roadmapPath, $queuePath, $preflightPath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "One-project proof-run file exists: $path"
    }

    $workflowText = Get-Content -LiteralPath $workflowPath -Raw -ErrorAction Stop
    $exampleText = Get-Content -LiteralPath $examplePath -Raw -ErrorAction Stop
    $roadmapText = Get-Content -LiteralPath $roadmapPath -Raw -ErrorAction Stop
    $queueText = Get-Content -LiteralPath $queuePath -Raw -ErrorAction Stop
    $preflightText = Get-Content -LiteralPath $preflightPath -Raw -ErrorAction Stop
    $combinedText = @($workflowText, $exampleText, $roadmapText, $queueText, $preflightText) -join "`n"

    foreach ($phrase in @(
        "One-Project Proof Run Workflow",
        "Evidence only; not executable authority or approval.",
        "exactly one registered project",
        "exactly one selected task",
        "launch gate before Codex",
        "Codex CLI/service_tier compatibility",
        "repo clean/dirty state",
        "task queue presence",
        "build/validation command presence",
        "checkpoint review after Codex edits",
        "stop for human review",
        "Phone/dashboard controls are request-only",
        'service_tier="fast"',
        'service_tier="default"',
        "powershell -NoProfile -ExecutionPolicy Bypass -File .\tools\fleet-proof-run-preflight.ps1 -ProjectId PrivateLens"
    )) {
        Assert-True -Condition ($workflowText -match [regex]::Escape($phrase)) -Message "One-project workflow preserves phrase: $phrase"
    }

    foreach ($phrase in @(
        "PrivateLens proved the v1 one-project proof-run pattern",
        'selected project only: `PrivateLens`',
        "one bounded task only",
        'configured build check passed: `npm.cmd run build`',
        'checkpoint review returned `GREEN`',
        "Fleet stopped for human review",
        "no merge, push, deploy",
        "The current PrivateLens task queue is empty after the successful proof"
    )) {
        Assert-True -Condition ($exampleText -match [regex]::Escape($phrase)) -Message "PrivateLens proof example preserves phrase: $phrase"
    }

    foreach ($phrase in @(
        "Phase 1.5: One-Project Proof-Run Workflow",
        "exactly one registered project",
        "exactly one selected task",
        "launch gate before Codex",
        "checkpoint review after Codex edits",
        "human review before merge, push, deploy",
        "Phone/dashboard controls remain request-only"
    )) {
        Assert-True -Condition ($roadmapText -match [regex]::Escape($phrase)) -Message "Roadmap preserves one-project proof-run phase: $phrase"
    }

    foreach ($phrase in @(
        "HQ-241 One-Project Proof-Run Workflow V1",
        "status: done",
        "docs/fleet/ONE_PROJECT_PROOF_RUN_WORKFLOW.md",
        "docs/fleet/ONE_PROJECT_PROOF_RUN_PRIVATE_LENS_EXAMPLE.md",
        "tools/fleet-proof-run-preflight.ps1",
        "powershell -NoProfile -ExecutionPolicy Bypass -File .\tools\fleet-proof-run-preflight.ps1 -ProjectId PrivateLens",
        "Do not modify product repos"
    )) {
        Assert-True -Condition ($queueText -match [regex]::Escape($phrase)) -Message "HQ queue records one-project proof-run workflow: $phrase"
    }

    foreach ($phrase in @(
        "exactly_one_project",
        "exactly_one_selected_task_for_actual_run",
        "repo_state_known",
        "task_queue_exists",
        "build_validation_command_exists",
        "launch_gate_script_exists",
        "checkpoint_review_script_exists",
        "codex_cli_detected",
        "service_tier_supported",
        "RequireSelectedTask",
        "Phone/dashboard controls: request/status only",
        "Forbidden operations remain blocked"
    )) {
        Assert-True -Condition ($preflightText -match [regex]::Escape($phrase)) -Message "Proof-run preflight checks boundary: $phrase"
    }

    foreach ($forbiddenBoundary in @(
        "secrets",
        "backend/auth/payments/deploy",
        "package installs",
        "migrations",
        "remote access",
        "all-fleet",
        "overnight runner",
        "merge, push, deploy",
        "broader authority",
        "phone/dashboard UI treated as execution authority"
    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($forbiddenBoundary)) -Message "One-project proof-run docs preserve forbidden boundary: $forbiddenBoundary"
    }

    Assert-False -Condition ($workflowText -match "(?is)(approves|authorizes|grants|permits).{0,140}(merge|push|deploy|all-fleet|overnight|future authority|product-repo authority)") -Message "One-project proof-run workflow does not grant forbidden authority"
    Assert-False -Condition ($exampleText -match "(?is)(approves|authorizes|grants|permits).{0,140}(PrivateLens|product-repo|merge|push|deploy|future authority)") -Message "PrivateLens proof example does not grant future product authority"

    $fixtureDir = Join-Path $fixtureRoot "one-project-proof-run"
    $fixtureRepo = Join-Path $fixtureDir "privatelens-fixture"
    $fixtureConfig = Join-Path $fixtureDir "projects.json"
    New-Item -ItemType Directory -Force -Path (Join-Path $fixtureRepo "docs\codex") | Out-Null
    Push-Location $fixtureRepo
    try {
        git init *> $null
        git config user.email "codex@example.local"
        git config user.name "Codex Test"
        @"
{
  "scripts": {
    "build": "echo build"
  }
}
"@ | Set-Content -LiteralPath "package.json" -Encoding UTF8
        @"
# Codex Task Queue

## Tasks

- [ ] User pain: confidence check. Skill: frontend-ui-engineering. Target: src/. Change: add one confidence display. First screen: keep workspace dominant. Guardrails: no backend/auth/payments/deploy/secrets/package installs. Acceptance: build passes. Check: npm.cmd run build [class:feature risk:low mode:single scope:src/]
"@ | Set-Content -LiteralPath "docs\codex\TASK_QUEUE.md" -Encoding UTF8
    } finally {
        Pop-Location
    }

    @(
        [pscustomobject]@{
            name = "PrivateLens"
            repo = $fixtureRepo
            buildDirectory = "."
            buildCommand = "npm.cmd run build"
        }
    ) | ConvertTo-Json -Depth 6 | Set-Content -LiteralPath $fixtureConfig -Encoding UTF8

    $shimRoot = Join-Path $fixtureDir "cli-shims"
    New-Item -ItemType Directory -Force -Path $shimRoot | Out-Null
    $originalPath = $env:PATH
    try {
        @"
@echo off
echo codex-cli-fixture 1.0.0
exit /b 0
"@ | Set-Content -LiteralPath (Join-Path $shimRoot "codex.cmd") -Encoding ASCII
        $env:PATH = "$shimRoot;$originalPath"

        $preflightOutput = @(& powershell -NoProfile -ExecutionPolicy Bypass -File $preflightPath -ConfigPath $fixtureConfig -ProjectId PrivateLens -TaskSelector "confidence check" -RequireSelectedTask 2>&1)
        $preflightExit = $LASTEXITCODE
        Assert-Equal -Actual $preflightExit -Expected 0 -Message "Proof-run preflight passes fixture with exactly one selected task"
        $preflightJoined = $preflightOutput -join "`n"
        foreach ($phrase in @(
            "PASS: exactly_one_project",
            "PASS: exactly_one_selected_task_for_actual_run",
            "PASS: task_queue_exists",
            "PASS: build_validation_command_exists",
            "PASS: launch_gate_script_exists",
            "PASS: checkpoint_review_script_exists",
            "PASS: codex_cli_detected - codex-cli-fixture 1.0.0",
            "Actual proof-run ready: True",
            "Preflight posture: GREEN"
        )) {
            Assert-True -Condition ($preflightJoined -match [regex]::Escape($phrase)) -Message "Proof-run preflight output preserves expected pass phrase: $phrase"
        }

        @"
@echo off
echo Access is denied 1>&2
exit /b 5
"@ | Set-Content -LiteralPath (Join-Path $shimRoot "codex.cmd") -Encoding ASCII

        $unreadableOutput = @(& powershell -NoProfile -ExecutionPolicy Bypass -File $preflightPath -ConfigPath $fixtureConfig -ProjectId PrivateLens -TaskSelector "confidence check" -RequireSelectedTask 2>&1)
        $unreadableExit = $LASTEXITCODE
        $unreadableJoined = $unreadableOutput -join "`n"
        Assert-Equal -Actual $unreadableExit -Expected 0 -Message "Proof-run preflight reports unreadable Codex CLI as controlled YELLOW"
        Assert-True -Condition ($unreadableJoined -match "WARN: codex_cli_detected") -Message "Proof-run preflight warns when Codex CLI version check fails"
        Assert-True -Condition ($unreadableJoined -match "version check failed") -Message "Proof-run preflight names failed Codex version check"
        Assert-True -Condition ($unreadableJoined -match "Actual proof-run ready: False") -Message "Proof-run preflight fails closed when Codex CLI is unreadable"
        Assert-True -Condition ($unreadableJoined -match "Preflight posture: YELLOW") -Message "Proof-run preflight keeps unreadable Codex as YELLOW, not GREEN"

        @"
@echo off
echo codex-cli-fixture 1.0.0
exit /b 0
"@ | Set-Content -LiteralPath (Join-Path $shimRoot "codex.cmd") -Encoding ASCII

        $blockedOutput = @(& powershell -NoProfile -ExecutionPolicy Bypass -File $preflightPath -ConfigPath $fixtureConfig -ProjectId PrivateLens -RequireSelectedTask 2>&1)
        $blockedExit = $LASTEXITCODE
        Assert-True -Condition ($blockedExit -ne 0) -Message "Proof-run preflight fails closed when actual run requires a task but none is selected"
        Assert-True -Condition (($blockedOutput -join "`n") -match "actual proof run requires exactly one selected task") -Message "Proof-run preflight names missing selected-task stop sign"
    } finally {
        $env:PATH = $originalPath
        Remove-Item -LiteralPath $shimRoot -Recurse -Force -ErrorAction SilentlyContinue
    }
}

function Test-HqPrivateLensCsvValidationProofTaskPacket {
    $packetPath = Join-Path $fleetRoot "docs\fleet\PRIVATE_LENS_CSV_VALIDATION_PROOF_TASK.md"
    $queuePath = Join-Path $fleetRoot "docs\fleet\HQ_REPAIR_TASK_QUEUE.md"

    foreach ($path in @($packetPath, $queuePath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "PrivateLens CSV validation proof packet file exists: $path"
    }

    $packetText = Get-Content -LiteralPath $packetPath -Raw -ErrorAction Stop
    $queueText = Get-Content -LiteralPath $queuePath -Raw -ErrorAction Stop
    $combinedText = @($packetText, $queueText) -join "`n"

    foreach ($phrase in @(
        "PrivateLens CSV Validation Proof Task",
        "Evidence only; not executable authority or approval.",
        'ProjectId: `PrivateLens`',
        'Quality mode: `best_value`',
        "Selected task: improve CSV validation/import warnings",
        "Selected task count: exactly one",
        "Selected project count: exactly one",
        "No PrivateLens files were modified during packet preparation.",
        "strict selected-task preflight requires a matching unchecked task in the registered PrivateLens task queue"
    )) {
        Assert-True -Condition ($packetText -match [regex]::Escape($phrase)) -Message "PrivateLens CSV proof packet preserves phrase: $phrase"
    }

    foreach ($futureFile in @(
        "docs/codex/TASK_QUEUE.md",
        "docs/codex/NIGHTLY_REPORT.md",
        "src/lib/parser.ts",
        "src/types.ts",
        "src/App.tsx",
        "src/App.css"
    )) {
        Assert-True -Condition ($packetText -match [regex]::Escape($futureFile)) -Message "PrivateLens CSV proof packet names future allowed file: $futureFile"
    }

    foreach ($phrase in @(
        "warn clearly on malformed CSV",
        "warn on missing or empty headers",
        "warn on inconsistent row lengths",
        "warn on unsupported or empty input",
        "preserve browser-only/local-first behavior",
        "preserve no upload/server path",
        "preserve no network calls",
        "preserve no persistence, local storage history, secrets, analytics, or tracking",
        "avoid a broad UI rewrite"
    )) {
        Assert-True -Condition ($packetText -match [regex]::Escape($phrase)) -Message "PrivateLens CSV proof packet preserves expected behavior: $phrase"
    }

    foreach ($command in @(
        "npm.cmd run build",
        "npm.cmd run lint",
        "powershell -NoProfile -ExecutionPolicy Bypass -File .\tools\fleet-proof-run-preflight.ps1 -ProjectId PrivateLens -TaskSelector `"CSV validation/import warnings`" -RequireSelectedTask"
    )) {
        Assert-True -Condition ($packetText -match [regex]::Escape($command)) -Message "PrivateLens CSV proof packet names validation command: $command"
    }

    foreach ($boundary in @(
        "secrets",
        "backend, auth, payments, deploy",
        "package installs",
        "migrations",
        "remote access",
        "all-fleet",
        "overnight runner",
        "broader authority",
        "merge, push, deploy",
        "files outside the future PrivateLens allowed files",
        "unclear scope",
        "phone/dashboard UI treated as execution authority"
    )) {
        Assert-True -Condition ($packetText -match [regex]::Escape($boundary)) -Message "PrivateLens CSV proof packet preserves stop boundary: $boundary"
    }

    foreach ($phrase in @(
        "HQ-242 PrivateLens CSV Validation Proof Task Packet",
        "status: done",
        "selectedProject:",
        "selectedTask:",
        "CSV validation/import warnings",
        "futurePrivateLensAllowedFiles:",
        "futureValidationCommands:",
        "Do not modify PrivateLens or run the proof run"
    )) {
        Assert-True -Condition ($queueText -match [regex]::Escape($phrase)) -Message "HQ queue records PrivateLens CSV proof packet: $phrase"
    }

    Assert-False -Condition ($packetText -match "(?is)(approves|authorizes|grants|permits).{0,140}(product-repo mutation|merge|push|deploy|all-fleet|overnight|future authority)") -Message "PrivateLens CSV proof packet does not grant forbidden authority"
