        "passwords",
        "MFA codes",
        "recovery codes",
        "keys",
        "tokens",
        "credentials",
        "private screenshots",
        "private device identifiers",
        "customer data",
        "product data"
    )) {
        Assert-True -Condition ($emergencyText -match [regex]::Escape($secretPhrase)) -Message "Emergency stop template rejects secret/sensitive field: $secretPhrase"
    }

    foreach ($forbidden in @(
        "process killing",
        "remote access configuration",
        "phone approval",
        "runtime command binding",
        "all-fleet",
        "overnight",
        "product-repo mutation",
        "deploy",
        "staging",
        "commit",
        "push",
        "install",
        "migration",
        "lock deletion",
        "permission widening",
        "secret-handling"
    )) {
        Assert-True -Condition ($emergencyText -match [regex]::Escape($forbidden)) -Message "Emergency stop template denies forbidden authority: $forbidden"
    }

    foreach ($phrase in @(
        'Emergency stop requests use `Emergency: REQUEST_STOP` and non-secret fields only',
        "not command execution, process killing, phone approval, runtime command binding, or product-repo authority",
        "Emergency Stop Request Rules",
        'Use `REQUEST_STOP` only as a cooperative request/signal',
        "Do not include PINs, passwords, MFA, recovery codes, keys, tokens, credentials",
        "A later HQ/Codex review must repacketize any stop handling into one bounded task before work starts."
    )) {
        Assert-True -Condition ($dashboardText -match [regex]::Escape($phrase)) -Message "Phone HQ dashboard preserves emergency stop rule: $phrase"
    }

    foreach ($phrase in @(
        "Emergency stop requests may contain only non-secret request fields",
        "Emergency stop does not approve product-repo mutation",
        "process killing",
        "shell/Codex command execution"
    )) {
        Assert-True -Condition ($securityText -match [regex]::Escape($phrase)) -Message "Phone HQ security model preserves emergency stop boundary: $phrase"
    }

    foreach ($phrase in @(
        "Emergency stop requests must carry only non-secret fields",
        "must be repacketized before any runner-side behavior",
        "do not approve process killing",
        "remote access configuration",
        "runtime command binding"
    )) {
        Assert-True -Condition ($architectureText -match [regex]::Escape($phrase)) -Message "Mobile architecture preserves emergency stop boundary: $phrase"
    }

    foreach ($phrase in @(
        "Emergency Stop Abuse Cases",
        '`REQUEST_STOP` text treated as a shell command',
        "emergency request used to kill processes from the public dashboard",
        "emergency request used to configure remote access",
        "emergency request used as phone approval",
        "emergency request containing PINs, passwords, MFA, recovery codes, keys, tokens, credentials",
        "Required control: emergency stop remains a high-priority request/signal"
    )) {
        Assert-True -Condition ($threatText -match [regex]::Escape($phrase)) -Message "Mobile threat model preserves emergency stop abuse case: $phrase"
    }

    foreach ($redPhrase in @(
        "run all-fleet",
        "run overnight",
        "deploy",
        "stage",
        "commit",
        "push",
        "install",
        "migrate",
        "delete locks",
        "widen permissions",
        "trigger GitHub Actions"
    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($redPhrase)) -Message "Emergency stop docs preserve RED forbidden path: $redPhrase"
    }

    Assert-False -Condition ($combinedText -match "STOP_ALL") -Message "Emergency stop contract avoids old STOP_ALL command-like label"
    Assert-True -Condition ($queueText -match "HQ-236 Emergency Stop Request Contract") -Message "HQ queue records emergency stop request contract task"
}

function Test-HqMobileControlPlaneArchitecture {
    $architecturePath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_SECURITY_ARCHITECTURE.md"
    $threatPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_THREAT_MODEL.md"
    $roadmapPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_ROADMAP.md"
    $schemaPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_REQUEST_SCHEMA.md"
    $queuePath = Join-Path $fleetRoot "docs\fleet\HQ_REPAIR_TASK_QUEUE.md"

    foreach ($path in @($architecturePath, $threatPath, $roadmapPath, $schemaPath, $queuePath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "Mobile control plane architecture doc exists: $path"
    }

    $architectureText = Get-Content -LiteralPath $architecturePath -Raw -ErrorAction Stop
    $threatText = Get-Content -LiteralPath $threatPath -Raw -ErrorAction Stop
    $roadmapText = Get-Content -LiteralPath $roadmapPath -Raw -ErrorAction Stop
    $schemaText = Get-Content -LiteralPath $schemaPath -Raw -ErrorAction Stop
    $queueText = Get-Content -LiteralPath $queuePath -Raw -ErrorAction Stop
    $combinedText = @($architectureText, $threatText, $roadmapText, $schemaText) -join "`n"

    foreach ($phrase in @(
        "public static dashboard",
        "authenticated user",
        "request object",
        "policy classification",
        "model routing / cost-quality recommendation",
        "allowedFiles",
        "validationCommands",
        "stopIf",
        "human/HQ approval where required",
        "runner-side execution gate",
        "audit log",
        "Product repo access is denied by default",
        "Mobile actions create signed or otherwise recorded requests",
        "Emergency stop must never become arbitrary command execution"
    )) {
        Assert-True -Condition ($architectureText -match [regex]::Escape($phrase)) -Message "Mobile architecture preserves requirement: $phrase"
    }

    foreach ($phrase in @(
        "Browser stores no GitHub PATs",
        "Browser never executes shell",
        "Phone approval is not execution authority",
        "Every executable request requires allowedFiles, validationCommands, stopIf, and one-task boundary",
        "Model routing / cost-quality recommendation",
        "Emergency stop is limited to audited stop signaling",
        "GitHub Actions misuse",
        "Least-privilege tokens"
    )) {
        Assert-True -Condition ($threatText -match [regex]::Escape($phrase)) -Message "Mobile threat model preserves requirement: $phrase"
    }

    foreach ($phrase in @(
        "Phase 0: Public Static HQ",
        "Phase 1: Polished Static Request Dashboard",
        "Phase 2: Authenticated Request Intake",
        "Phase 3: Policy Gate And Model Router",
        "Phase 4: Controlled Runner Integration",
        "Phase 5: Audited Project Control",
        "no public command buttons",
        "no client-side secrets",
        "no broad repo access",
        "no phone approval as execution authority",
        "no all-fleet from mobile",
        "no deploys from public dashboard"
    )) {
        Assert-True -Condition ($roadmapText -match [regex]::Escape($phrase)) -Message "Mobile roadmap preserves requirement: $phrase"
    }

    foreach ($field in @(
        "requestId",
        "createdAt",
        "requester",
        "project",
        "taskSummary",
        "qualityMode",
        "requestedModelTier",
        "filesRequested",
        "forbiddenOperations",
        "validationRequested",
        "approvalRequired",
        "emergencyStop",
        "status",
        "auditNotes"
    )) {
        Assert-True -Condition ($schemaText -match [regex]::Escape($field)) -Message "Mobile request schema includes field: $field"
    }

    Assert-True -Condition ($schemaText -match "best_value" -and $schemaText -match "perfection") -Message "Mobile request schema supports best_value and perfection quality modes"
    Assert-True -Condition ($schemaText -match "one-task boundary" -and $schemaText -match "allowedFiles" -and $schemaText -match "validationCommands" -and $schemaText -match "stopIf") -Message "Mobile request schema preserves executable task contract"
    Assert-True -Condition ($combinedText -match "no direct browser command execution" -or $combinedText -match "direct browser command execution") -Message "Mobile control plane rejects direct browser command execution"
    Assert-True -Condition ($combinedText -match "no client-side secrets" -or $combinedText -match "browser must never store") -Message "Mobile control plane rejects client-side secrets"

    foreach ($phrase in @(
        "Implementation Cutline",
        "not approval to begin authenticated request intake",
        "authentication design",
        "secret storage boundary",
        "request integrity",
        "policy gate",
        "allowedFiles",
        "validationCommands",
        "stopIf",
        "model routing / cost-quality recommendation",
        "runner refusal behavior",
        "audit logs",
        "human approval rules",
        "does not approve backend/auth/execution/GitHub Actions implementation",
        "separate one-task implementation packet"
    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($phrase)) -Message "Mobile control plane preserves implementation cutline: $phrase"
    }

    foreach ($nonGoal in @(
        "no authentication or backend implementation in this architecture task",
        "no backend/auth/execution/GitHub Actions implementation approved by architecture docs alone",
        "no runner integration until runner refusal behavior and audit logs are separately validated"
    )) {
        Assert-True -Condition ($roadmapText -match [regex]::Escape($nonGoal)) -Message "Mobile roadmap preserves implementation non-goal: $nonGoal"
    }

    Assert-True -Condition ($threatText -match "Premature control-plane implementation") -Message "Mobile threat model covers premature implementation"
    Assert-True -Condition ($schemaText -match "Authenticated Intake Cutline") -Message "Mobile request schema preserves authenticated intake cutline"
    Assert-True -Condition ($queueText -match "HQ-237 Mobile Control Plane Implementation Cutline") -Message "HQ queue records mobile control plane implementation cutline task"
}

function Test-HqModelRoutingPolicySpec {
    $policyPath = Join-Path $fleetRoot "docs\fleet\MODEL_ROUTING_POLICY.md"
    $fixturesPath = Join-Path $fleetRoot "docs\fleet\MODEL_ROUTING_FIXTURES.md"
    $roadmapPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_ROADMAP.md"
    $queuePath = Join-Path $fleetRoot "docs\fleet\HQ_REPAIR_TASK_QUEUE.md"

    foreach ($path in @($policyPath, $fixturesPath, $roadmapPath, $queuePath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "Model routing policy doc exists: $path"
    }

    $policyText = Get-Content -LiteralPath $policyPath -Raw -ErrorAction Stop
    $fixturesText = Get-Content -LiteralPath $fixturesPath -Raw -ErrorAction Stop
    $roadmapText = Get-Content -LiteralPath $roadmapPath -Raw -ErrorAction Stop
    $queueText = Get-Content -LiteralPath $queuePath -Raw -ErrorAction Stop
    $combinedText = @($policyText, $fixturesText, $roadmapText, $queueText) -join "`n"

    foreach ($phrase in @(
        "Evidence only; not executable authority or approval.",
        "best_value",
        "perfection",
        "fast_readonly",
        "standard_patch",
        "deep_reasoning",
        "premium_audit",
        "scope",
        "risk",
        "ambiguity",
        "validation strength",
        "token pressure",
        "failure cost"
    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($phrase)) -Message "Model routing policy preserves phrase: $phrase"
    }

    foreach ($trigger in @(
        "repeated uncertainty",
        "validation failed twice",
        "security boundary unclear",
        "high token pressure",
        "product/deploy/secrets boundary",
        'explicit Tim "perfect" request'
    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($trigger)) -Message "Model routing policy preserves escalation trigger: $trigger"
    }

    foreach ($blocked in @(
        "secrets",
        "unauthorized product repo access",
        "deploy/merge/push",
        "all-fleet",
        "overnight runner",
        "broad authority"
    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($blocked)) -Message "Model routing policy preserves blocked condition: $blocked"
    }

    Assert-True -Condition ($combinedText -match "aliases only" -and $combinedText -match "Do not hardcode current model names") -Message "Model routing policy is alias-only"
    Assert-True -Condition ($roadmapText -match "Phase 3 model routing starts as an alias-only policy specification") -Message "Mobile roadmap records alias-only model routing cutline"
    Assert-True -Condition ($queueText -match "HQ-243 Model Routing Policy Spec V1") -Message "HQ queue records model routing policy task"
    Assert-False -Condition ($policyText -match "(?i)\b(gpt|claude|gemini|llama|mistral|o[0-9])[-A-Za-z0-9.]*\b") -Message "Model routing policy avoids hardcoded current model names"
    Assert-False -Condition ($fixturesText -match "(?i)\b(gpt|claude|gemini|llama|mistral|o[0-9])[-A-Za-z0-9.]*\b") -Message "Model routing fixtures avoid hardcoded current model names"
    Assert-False -Condition ($combinedText -match "(?i)(cost per|dollar|usd|\$[0-9])") -Message "Model routing docs avoid current pricing claims"
    Assert-False -Condition ($combinedText -match "(?i)(call model APIs|wire routing into live execution|approve any Codex run).*(allowed|enabled|implemented)") -Message "Model routing docs do not wire execution"
}

function Test-HqModelRoutingPreflightHelper {
    $helperPath = Join-Path $fleetRoot "tools\fleet-model-routing-preflight.ps1"
    $packetPath = Join-Path $fleetRoot "docs\fleet\PRIVATE_LENS_CSV_VALIDATION_PROOF_TASK.md"
    $policyPath = Join-Path $fleetRoot "docs\fleet\MODEL_ROUTING_POLICY.md"
    $fixturesPath = Join-Path $fleetRoot "docs\fleet\MODEL_ROUTING_FIXTURES.md"
    $roadmapPath = Join-Path $fleetRoot "docs\fleet\MOBILE_CONTROL_PLANE_ROADMAP.md"
    $queuePath = Join-Path $fleetRoot "docs\fleet\HQ_REPAIR_TASK_QUEUE.md"

    foreach ($path in @($helperPath, $packetPath, $policyPath, $fixturesPath, $roadmapPath, $queuePath)) {
        Assert-True -Condition (Test-Path -LiteralPath $path) -Message "Model routing preflight path exists: $path"
    }

    $result = Invoke-Checked -FilePath "powershell" -Arguments @("-NoProfile", "-ExecutionPolicy", "Bypass", "-File", $helperPath, "-TaskPacket", "docs\fleet\PRIVATE_LENS_CSV_VALIDATION_PROOF_TASK.md")
    Assert-Equal -Actual $result.exitCode -Expected 0 -Message "Model routing preflight runs against PrivateLens packet"
    $routing = ($result.output -join "`n") | ConvertFrom-Json -ErrorAction Stop
    Assert-Equal -Actual $routing.qualityMode -Expected "best_value" -Message "Model routing preflight observes PrivateLens quality mode"
    Assert-Equal -Actual $routing.recommendationStatus -Expected "GREEN" -Message "Model routing preflight marks PrivateLens packet green"
    Assert-Equal -Actual $routing.recommendedModelAlias -Expected "standard_patch" -Message "Model routing preflight recommends standard patch for PrivateLens packet"
    Assert-True -Condition ([bool]$routing.recommendationOnly) -Message "Model routing preflight is recommendation-only"
    Assert-False -Condition ([bool]$routing.executesTasks) -Message "Model routing preflight does not execute tasks"
    Assert-False -Condition ([bool]$routing.modifiesTaskPacket) -Message "Model routing preflight does not modify task packets"
    Assert-False -Condition ([bool]$routing.callsModelApis) -Message "Model routing preflight does not call model APIs"
    foreach ($alias in @("fast_readonly", "standard_patch", "deep_reasoning", "premium_audit")) {
        Assert-True -Condition (@($routing.allowedAliases) -contains $alias) -Message "Model routing preflight exposes alias: $alias"
    }

    $blockedPacketPath = Join-Path $fixtureRoot "model-routing-blocked-packet.md"
    Set-Content -LiteralPath $blockedPacketPath -Encoding UTF8 -Value @"
# Blocked Model Routing Packet

qualityMode: best_value

allowedFiles:
- any product repo file

validationCommands:
- none

This packet authorizes deploy, merge, push, all-fleet execution, an overnight runner, and broader authority.
"@
    $blockedResult = Invoke-Checked -FilePath "powershell" -Arguments @("-NoProfile", "-ExecutionPolicy", "Bypass", "-File", $helperPath, "-TaskPacket", $blockedPacketPath)
    Assert-Equal -Actual $blockedResult.exitCode -Expected 0 -Message "Model routing preflight reports blocked packets without executing"
    $blockedRouting = ($blockedResult.output -join "`n") | ConvertFrom-Json -ErrorAction Stop
    Assert-Equal -Actual $blockedRouting.recommendationStatus -Expected "BLOCKED" -Message "Model routing preflight recognizes blocked conditions"
    Assert-True -Condition ([string]::IsNullOrWhiteSpace([string]$blockedRouting.recommendedModelAlias)) -Message "Blocked model routing packets receive no alias"
    Assert-True -Condition (((@($blockedRouting.blockedConditionsFound) -join "`n") -match "deploy/merge/push") -and ((@($blockedRouting.blockedConditionsFound) -join "`n") -match "all-fleet")) -Message "Model routing preflight lists blocked condition categories"

    $helperText = Get-Content -LiteralPath $helperPath -Raw -ErrorAction Stop
    $combinedText = @(
        $helperText,
        (Get-Content -LiteralPath $policyPath -Raw -ErrorAction Stop),
        (Get-Content -LiteralPath $fixturesPath -Raw -ErrorAction Stop),
        (Get-Content -LiteralPath $roadmapPath -Raw -ErrorAction Stop)
    ) -join "`n"
    Assert-False -Condition ($helperText -match "(?i)\b(gpt|claude|gemini|llama|mistral|o[0-9])[-A-Za-z0-9.]*\b") -Message "Model routing preflight avoids hardcoded current model names"
    Assert-False -Condition ($combinedText -match "(?i)(cost per|dollar|usd|\$[0-9])") -Message "Model routing preflight docs avoid current pricing claims"
    Assert-False -Condition ($combinedText -match "(?i)(executes tasks|mutate task packets|change Codex config|approve product-repo access).*(true|allowed|enabled)") -Message "Model routing preflight remains recommendation-only"
    Assert-True -Condition ((Get-Content -LiteralPath $queuePath -Raw -ErrorAction Stop) -match "HQ-244 Model Routing Preflight Helper V1") -Message "HQ queue records model routing preflight helper task"
}

function Test-FixtureGeneration {
    $generator = Join-Path $fleetRoot "tests\new-fixture-ships.ps1"
    $generatorText = Get-Content $generator -Raw
    $result = Invoke-Checked -FilePath "powershell" -Arguments @("-NoProfile", "-ExecutionPolicy", "Bypass", "-File", $generator, "-Force")
    Assert-Equal -Actual $result.exitCode -Expected 0 -Message "Fixture ship generator exits successfully"
    Assert-True -Condition (Test-Path $fixtureConfig) -Message "Fixture project config exists"

    $parsedProjects = Get-Content $fixtureConfig -Raw | ConvertFrom-Json
    $projects = @($parsedProjects | ForEach-Object { $_ })
    Assert-Equal -Actual $projects.Count -Expected 3 -Message "Fixture config contains three ships"
    Assert-True -Condition ($generatorText -match 'PresentationWorkloads') -Message "Fixture generator supports presentation-specific workload tasks"
    Assert-True -Condition ($generatorText -match 'impact:\$taskImpact' -and $generatorText -match '\$DocsOnly.+standard') -Message "Presentation docs-only fixtures use standard impact instead of visible-impact"
    Assert-True -Condition ($generatorText -match 'UseRealModels' -and $generatorText -match 'gpt-5\.4-mini') -Message "Fixture generator can use supported low-cost real models for live smoke runs"
}

function Test-PhaseZeroIntakeSupport {
    $allowedProjectTypes = @("marketing-site", "full-stack-web", "desktop-app", "cli-tool", "library", "data-pipeline", "ai-workflow", "mobile-app", "game", "documentation", "sandbox-prototype")
    $allowedRiskTiers = @("sandbox", "local-only", "staging", "production-adjacent", "production")
    $capabilityNames = @("canEditPackageFiles", "canAddDependencies", "canEditBackendCode", "canEditMigrations", "canEditAuthPolicy", "canEditDeploymentConfig", "canUseNetworkApis", "canOpenPullRequests", "canDeploy")

    foreach ($profilePath in @(Get-ChildItem (Join-Path $fleetRoot "profiles") -Filter "*.json")) {
        $profile = Get-Content $profilePath.FullName -Raw | ConvertFrom-Json
        Assert-True -Condition ($allowedProjectTypes -contains [string]$profile.projectType) -Message "$($profile.name) profile has a valid projectType"
        Assert-True -Condition ($allowedRiskTiers -contains [string]$profile.riskTier) -Message "$($profile.name) profile has a valid riskTier"
        foreach ($capabilityName in $capabilityNames) {
            Assert-True -Condition ($null -ne $profile.capabilities.PSObject.Properties[$capabilityName]) -Message "$($profile.name) profile declares $capabilityName"
        }
    }

    $addProjectText = Get-Content (Join-Path $fleetRoot "add-project.ps1") -Raw
    $doctorText = Get-Content (Join-Path $fleetRoot "fleet-doctor.ps1") -Raw
    $readmeText = Get-Content (Join-Path $fleetRoot "README.md") -Raw

    Assert-True -Condition ($addProjectText -match '\[string\]\$ProjectType') -Message "add-project accepts project type intake metadata"
    Assert-True -Condition ($addProjectText -match '\[string\]\$RiskTier') -Message "add-project accepts risk tier intake metadata"
    Assert-True -Condition ($addProjectText -match '\[string\[\]\]\$Capability') -Message "add-project accepts capability intake metadata"
    Assert-True -Condition ($doctorText -match 'Resolve-IntakeMetadata') -Message "Fleet doctor resolves Phase 0 intake metadata"
    Assert-True -Condition ($doctorText -match 'Unknown projectType') -Message "Fleet doctor blocks unknown project types"
    Assert-True -Condition ($doctorText -match 'Unknown riskTier') -Message "Fleet doctor blocks unknown risk tiers"
    Assert-True -Condition ($doctorText -match '-split ","') -Message "Fleet doctor accepts comma-packed project exclusions"
    Assert-True -Condition ($readmeText -match 'Phase 0 intake metadata') -Message "README documents Phase 0 intake metadata"
}

