    Assert-True -Condition ((Get-Content (Join-Path $fleetRoot "debug-checkpoint.ps1") -Raw) -match '\(GREEN\|YELLOW\|RED\)\\b\[\\s\\\.') -Message "Checkpoint debugger accepts verdict punctuation"
