        "MAKE_AUDIT_PACKAGE",
        "IMPORT_APPROVED_PACKET",
        "WRITE_REPAIR_TASK",
        "PARK_SHIP",
        "REQUEST_TASTE_GATE",
        "BLOCK_WITH_REASON"
