    }

    $validationProperties = $schema.properties.validation.properties
    foreach ($reason in @(
        "selected-ship-present",
        "blank-ship",
        "all-ship",
        "wildcard-ship",
        "multi-ship",
        "forbidden-scope",
        "missing-approval",
        "stale-fingerprint",
        "legacy-broad-entrypoint",
        "external-report-non-executable",
        "mobile-request-non-executable",
