    )) {
        Assert-True -Condition ($combinedText -match [regex]::Escape($phrase)) -Message "Runtime enforcement deferral boundary preserves phrase: $phrase"
    }

    foreach ($blocked in @(
        "product-repo mutation",
        "ship launches",
        "all-fleet commands",
        "package installation",
        "migrations",
        "secrets/auth/payments/deploy",
        "lock deletion",
