    )) {
        Assert-True -Condition ($modelText -match [regex]::Escape($phrase)) -Message "Service Sync Studio model preserves phrase: $phrase"
    }

    foreach ($phrase in @(
        "staff performance",
        "guest identity",
        "manager-only margin",
        "vendor pricing",
        "incident",
        "secrets",
        "credentials",
        "payment details",
        "auth material",
