        "Run only",
        "recommended post-spike review outcome"
    )) {
        Assert-True -Condition ($thinPacketText -match [regex]::Escape($phrase)) -Message "Service Sync Studio HQ-221 thin packet preserves phrase: $phrase"
    }

    foreach ($phrase in @(
